  "Anti-Forensics Indicators": [
    { artifact: "Timestomping Evidence (MFT vs $LogFile)", locations: ["C:\\$MFT", "C:\\$LogFile", "C:\\$Extend\\$UsnJrnl"], tools: ["MFTECmd", "NTFS Log Tracker", "Plaso"], reveals: "$STANDARD_INFORMATION timestamps modified but $FILE_NAME timestamps unchanged — classic timestomping pattern. $LogFile and USN Journal retain original operation timestamps at time of file creation/modification", eventIds: [], mitre: ["T1070.006"], commands: [{ label: "Compare SI vs FN timestamps with MFTECmd", cmd: "MFTECmd.exe -f C:\\$MFT --csv C:\\output --dedupe" }], related: ["NTFS MFT ($MFT)", "NTFS USN Journal ($UsnJrnl:$J)"], retention: "$LogFile has very short retention (often minutes to hours); USN Journal retention is longer but still finite — capture both quickly after suspected timestomping.", sources: ["SANS FOR500", "Mandiant timestomping detection research"] },
    { artifact: "Event Log Cleared", locations: ["%SystemRoot%\\System32\\winevt\\Logs\\Security.evtx", "System.evtx"], tools: ["EvtxECmd", "Hayabusa"], reveals: "Security log cleared (1102), System log cleared (104) — who cleared it and when. Primary anti-forensics indicator. Log clearing itself leaves an event", eventIds: ["1102","104"], mitre: ["T1070.001"], commands: [{ label: "Filter log-cleared events", cmd: 'wevtutil qe Security /q:"*[System[(EventID=1102)]]" /f:text' }], related: ["Security Event Log — Logon Events"], retention: "The clear event itself is typically the first entry in a freshly-cleared log — check both Security and System logs since clearing one is often accompanied by clearing the other.", sources: ["SANS FOR508", "MITRE ATT&CK T1070.001"] },
    { artifact: "Volume Shadow Copy Deletion Evidence", locations: ["Security/System Event Logs", "Prefetch"], tools: ["EvtxECmd", "PECmd"], reveals: "VSS deletion commands in Prefetch (vssadmin.exe, wmic.exe, powershell.exe) and event logs — ransomware signature. vssadmin delete shadows /all /quiet", eventIds: [], mitre: ["T1490"], commands: [{ label: "Check Prefetch for vssadmin execution", cmd: "PECmd.exe -f C:\\Windows\\Prefetch\\VSSADMIN.EXE-*.pf" }], related: ["Volume Shadow Copies (VSS)", "Prefetch Files"], retention: "Prefetch entries persist per normal Prefetch rotation; event log entries follow the source log's own rotation policy.", sources: ["SANS FOR508", "MITRE ATT&CK T1490"] },
    { artifact: "Sysinternals Tool EULA Keys", locations: ["HKCU\\Software\\Sysinternals\\[tool]\\EulaAccepted"], tools: ["Registry Explorer", "RegRipper"], reveals: "EULA accepted proves specific Sysinternals tools were run — PsExec, Procdump, ProcMon, etc. Corroborate with Prefetch and AmCache", eventIds: [], mitre: ["T1059", "T1570"], commands: [{ label: "Query Sysinternals EULA keys", cmd: 'reg query "HKCU\\Software\\Sysinternals" /s' }], related: ["Prefetch Files", "AmCache.hve"], retention: "Persists indefinitely in the user's registry hive until manually removed.", sources: ["SANS FOR508"] },
  ],
